.darma-loader-darma-custom-553 {color: var(--loader-color, #0891b2);
   width: 30px;
   aspect-ratio: 1;
   display: grid;
}
.darma-loader-darma-custom-553, .darma-loader-darma-custom-553:before, .darma-loader-darma-custom-553:after  {
  --c:no-repeat linear-gradient(var(--loader-color, #0891b2) 0 0);
   background:var(--c), var(--c), var(--c), var(--c);
   animation: darma-loader-darma-custom-553-l19-1 1.5s infinite, darma-loader-darma-custom-553-l19-2 1.5s infinite;
}
.darma-loader-darma-custom-553:before, .darma-loader-darma-custom-553:after  {
  content: "";
   grid-area: 1/1;
   transform: translate(calc(50% - 2px),calc(2px - 50%)) rotate(90deg);
   animation-delay: -.25s;
}
.darma-loader-darma-custom-553:after  {
  transform: translate(calc(2px - 50%),calc(50% - 2px)) rotate(90deg);
}
@keyframes darma-loader-darma-custom-553-l19-1  {
  0%, 10% {background-size: 0 4px,4px 0 }
40%, 60% {background-size: 100% 4px,4px 100%}
90%, 100% {background-size: 0 4px,4px 0 }
}
@keyframes darma-loader-darma-custom-553-l19-2  {
  0%,49.9%{background-position: 0 0,0 0,100% 100%,100% 100%}
50%,100%{background-position: 100% 0,0 100%,0 100%,100% 0}
}

